import React from "react";
import "./App.css";

const App = () => {
  return (
    <div className="app">
      <header className="app__header">
        <h1>SmartSpend</h1>
        <p>Frontend scaffold restored. You can now build your screens.</p>
      </header>
    </div>
  );
};

export default App;
